using System;
using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Implementação concreta de INpcChoiceMenu: menu de escolhas usando Button (UGUI).
///
/// Configuração esperada (montar no Editor, dentro de um Canvas):
/// - "panelRoot": GameObject raiz do menu (activado/desactivado em Show).
/// - "buttonContainer": Transform onde os botões de escolha são instanciados
///   (normalmente com um Vertical Layout Group para os empilhar).
/// - "choiceButtonPrefab": prefab de Button com um TMP_Text filho para mostrar
///   o texto da escolha.
///
/// A navegação entre escolhas usa o sistema automático de Selectable/EventSystem
/// do Unity UI (setas/d-pad + botão de confirmar do Input System UI Input
/// Module) — não há código de navegação próprio aqui. No início de cada
/// Show(), o primeiro botão é seleccionado automaticamente.
///
/// Atribui este componente ao campo "Choice Menu" do(s) NpcController(s).
/// </summary>
public class NpcChoiceMenuUI : MonoBehaviour, INpcChoiceMenu
{
    [Header("Referências")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private Transform buttonContainer;
    [SerializeField] private Button choiceButtonPrefab;

    private readonly List<GameObject> _spawned = new List<GameObject>();

    private void Awake()
    {
        if (panelRoot != null)
            panelRoot.SetActive(false);
    }

    public IEnumerator Show(NpcController npc, List<NpcChoice> choices, Action<int> onSelected)
    {
        if (choiceButtonPrefab == null || buttonContainer == null)
        {
            Debug.LogWarning($"[{name}] NpcChoiceMenuUI: 'choiceButtonPrefab' ou 'buttonContainer' não atribuídos.", this);
            onSelected?.Invoke(-1);
            yield break;
        }

        ClearButtons();

        if (panelRoot != null) panelRoot.SetActive(true);

        int? selected = null;

        for (int i = 0; i < choices.Count; i++)
        {
            int index = i; // captura por valor para o listener

            var button = Instantiate(choiceButtonPrefab, buttonContainer);
            button.gameObject.SetActive(true);

            var label = button.GetComponentInChildren<TMP_Text>();
            if (label != null) label.text = choices[i].text;

            button.onClick.AddListener(() => selected = index);

            _spawned.Add(button.gameObject);
        }

        // Selecciona o primeiro botão para permitir navegação imediata por teclado/gamepad.
        if (_spawned.Count > 0 && EventSystem.current != null)
        {
            EventSystem.current.SetSelectedGameObject(null);
            EventSystem.current.SetSelectedGameObject(_spawned[0]);
        }

        while (selected == null)
            yield return null;

        ClearButtons();

        if (panelRoot != null) panelRoot.SetActive(false);

        onSelected?.Invoke(selected.Value);
    }

    private void ClearButtons()
    {
        foreach (var go in _spawned)
        {
            if (go != null) Destroy(go);
        }

        _spawned.Clear();
    }
}
